(() => {
    interface Circular {
      n: number;
      s: string;
      c?: Circular;
      d?: Date;
    }
    return {build: () => createValidate<Circular>(), buildErrors: () => noErrs(createGetValidationErrors<Circular>())};
  })()

() => {
    const cir = RT.circular((self) =>
      RT.object({
        n: RT.number(),
        s: RT.string(),
        c: RT.optional(self),
        d: RT.optional(RT.date()),
      })
    );
    return createValidate(cir);
  }

{
    build: () => {
      interface Circular {
        n: number;
        s: string;
        c?: Circular;
        d?: Date;
      }
      const check = typia.createIs<Circular>();
      return (v) => check(v);
    },
    buildErrors: () => {
      interface Circular {
        n: number;
        s: string;
        c?: Circular;
        d?: Date;
      }
      const val = typia.createValidate<Circular>();
      return (v) => val(v).success;
    },
    samples: {
      invalid: [
        {n: 1, s: 'hello', c: {n: 2, s: 123}},
        {n: 1, s: 'hello', c: {n: 2}},
        null,
        undefined,
        {n: 1, s: 'x', d: 'not date'},
        {},
      ],
    },
  }

c(
    Type.Recursive((This) =>
      Type.Object({
        n: Type.Number(),
        s: Type.String(),
        c: Type.Optional(This),
        d: Type.Optional(Type.Date()),
      })
    )
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.object({
      n: z.number().finite(),
      s: z.string(),
      c: z.lazy(() => schema).optional(),
      d: z.date().optional(),
    });
    return schema;
  }))
